245	func (f *CommandFactory) runAgentWorkers(cmd *cobra.Command, _ []string) error {
246		asJSON, _ := cmd.Flags().GetBool("json")
247		watch, _ := cmd.Flags().GetBool("watch")
248		projectFlag, _ := cmd.Flags().GetString("project")
249	
250		projectRoot := projectFlag
251		if projectRoot == "" {
252			projectRoot = gitpkg.FindProjectRoot(f.WorkingDir)
253		}
254	
255		render := func(out io.Writer) error {
256			workers := collectAgentWorkers(projectRoot)
257			if asJSON {
258				enc := json.NewEncoder(out)
259				enc.SetIndent("", "  ")
260				return enc.Encode(workers)
261			}
262			return printAgentWorkersTable(out, workers)
263		}
264	
265		if !watch {
266			return render(cmd.OutOrStdout())
267		}
268	
269		ctx := cmd.Context()
270		for {
271			// Clear screen and move cursor to top-left
272			fmt.Fprint(cmd.OutOrStdout(), "\033[2J\033[H")
273			fmt.Fprintf(cmd.OutOrStdout(), "Workers — %s  (Ctrl-C to stop)\n\n",
274				time.Now().Format("15:04:05"))
275			if err := render(cmd.OutOrStdout()); err != nil {
276				return err
277			}
278			select {
279			case <-ctx.Done():
280				return nil
281			case <-time.After(2 * time.Second):
282			}
283		}
284	}
