355	// agentLocalManifest is a minimal representation of .ddx/executions/{id}/manifest.json.
356	type agentLocalManifest struct {
357		AttemptID string    `json:"attempt_id"`
358		WorkerID  string    `json:"worker_id,omitempty"`
359		BeadID    string    `json:"bead_id"`
360		CreatedAt time.Time `json:"created_at"`
361		Requested struct {
362			Harness string `json:"harness,omitempty"`
363			Model   string `json:"model,omitempty"`
364		} `json:"requested"`
365		Bead struct {
366			ID    string `json:"id"`
367			Title string `json:"title"`
368		} `json:"bead"`
369	}
