371	// scanLocalBeadWorkers scans .ddx/executions/*/manifest.json and checks
372	// active git worktrees to find locally-running execute-bead executions
373	// not already covered by the server.
374	func scanLocalBeadWorkers(projectRoot string, serverAttemptIDs map[string]bool) []agentWorkerDisplay {
375		execDir := filepath.Join(projectRoot, ".ddx", "executions")
376		entries, err := os.ReadDir(execDir)
377		if err != nil {
378			return nil
379		}
380	
381		active := agentActiveWorktrees(projectRoot)
382	
383		var out []agentWorkerDisplay
384		for _, entry := range entries {
385			if !entry.IsDir() {
386				continue
387			}
388			manifestPath := filepath.Join(execDir, entry.Name(), "manifest.json")
389			data, err := os.ReadFile(manifestPath)
390			if err != nil {
391				continue
392			}
393			var m agentLocalManifest
394			if err := json.Unmarshal(data, &m); err != nil {
395				continue
396			}
397	
398			// Skip if covered by server (attempt already tracked)
399			if serverAttemptIDs[m.AttemptID] {
400				continue
401			}
402			// Skip if worker_id is set — server-submitted executions are in the server list
403			if m.WorkerID != "" {
404				continue
405			}
406	
407			// Check if the worktree for this attempt is still active
408			wtPath := agentLocalWorktreePath(m.BeadID, m.AttemptID)
409			if !active[wtPath] {
410				continue
411			}
412	
413			elapsed := time.Since(m.CreatedAt)
414			d := agentWorkerDisplay{
415				ID:        "local-" + m.AttemptID,
416				Kind:      "local",
417				State:     "running",
418				BeadID:    m.BeadID,
419				BeadTitle: m.Bead.Title,
420				Harness:   m.Requested.Harness,
421				Model:     m.Requested.Model,
422				StartedAt: m.CreatedAt,
423				ElapsedMS: elapsed.Milliseconds(),
424			}
425			out = append(out, d)
426		}
427		return out
428	}
429	
430	// agentLocalWorktreePath reconstructs the absolute path of an execute-bead
431	// worktree for the given bead and attempt IDs. Mirrors executeBeadWorktreePath
432	// in internal/agent/execute_bead.go.
433	func agentLocalWorktreePath(beadID, attemptID string) string {
434		base := os.Getenv("DDX_EXEC_WT_DIR")
435		if base == "" {
436			base = filepath.Join(os.TempDir(), agent.ExecuteBeadTmpSubdir)
437		}
438		return filepath.Join(base, agent.ExecuteBeadWtPrefix+beadID+"-"+attemptID)
439	}
440	
441	// agentActiveWorktrees returns a set of absolute worktree paths currently
442	// registered in the git repository at projectRoot.
443	func agentActiveWorktrees(projectRoot string) map[string]bool {
444		out, err := gitpkg.Command(context.Background(), projectRoot, "worktree", "list", "--porcelain").Output()
445		if err != nil {
446			return nil
447		}
448		paths := make(map[string]bool)
449		for _, line := range strings.Split(string(out), "\n") {
450			if strings.HasPrefix(line, "worktree ") {
451				paths[strings.TrimPrefix(line, "worktree ")] = true
452			}
453		}
454		return paths
455	}
