457	// printAgentWorkersTable renders the workers list as a tab-aligned table.
458	func printAgentWorkersTable(w io.Writer, workers []agentWorkerDisplay) error {
459		if len(workers) == 0 {
460			_, err := fmt.Fprintln(w, "no active workers")
461			return err
462		}
463	
464		tw := tabwriter.NewWriter(w, 0, 0, 2, ' ', 0)
465		fmt.Fprintln(tw, "STATE\tBEAD\tTITLE\tHARNESS\tMODEL\tELAPSED\tATTEMPTS")
466		for _, wk := range workers {
467			beadID := wk.BeadID
468			if beadID == "" {
469				beadID = "-"
470			}
471			title := agentTruncateTitle(wk.BeadTitle, 40)
472			if title == "" {
473				title = "-"
474			}
475			harness := wk.Harness
476			if harness == "" {
477				harness = "-"
478			}
479			model := wk.Model
480			if model == "" {
481				model = "-"
482			}
483			elapsed := agentFormatElapsed(wk.ElapsedMS, wk.StartedAt)
484			attempts := fmt.Sprintf("%d", wk.Attempts)
485	
486			fmt.Fprintf(tw, "%s\t%s\t%s\t%s\t%s\t%s\t%s\n",
487				wk.State, beadID, title, harness, model, elapsed, attempts)
488		}
489		return tw.Flush()
490	}
491	
492	// agentTruncateTitle truncates s to at most max runes, appending "…" if truncated.
493	func agentTruncateTitle(s string, max int) string {
494		runes := []rune(s)
495		if len(runes) <= max {
496			return s
497		}
498		return string(runes[:max-1]) + "…"
499	}
500	
501	// agentFormatElapsed returns a human-readable elapsed duration like "4m32s".
502	// Uses elapsedMS if positive; otherwise derives from startedAt.
503	func agentFormatElapsed(elapsedMS int64, startedAt time.Time) string {
504		var d time.Duration
505		if elapsedMS > 0 {
506			d = time.Duration(elapsedMS) * time.Millisecond
507		} else if !startedAt.IsZero() {
508			d = time.Since(startedAt)
509			if d < 0 {
510				d = 0
511			}
512		} else {
513			return "-"
514		}
515		h := int(d.Hours())
516		m := int(d.Minutes()) % 60
517		s := int(d.Seconds()) % 60
518		if h > 0 {
519			return fmt.Sprintf("%dh%dm%ds", h, m, s)
520		}
521		if m > 0 {
522			return fmt.Sprintf("%dm%ds", m, s)
523		}
524		return fmt.Sprintf("%ds", s)
525	}
