12	// InstalledEntry records an installed package.
13	type InstalledEntry struct {
14		Name        string      `yaml:"name"`
15		Version     string      `yaml:"version"`
16		Type        PackageType `yaml:"type"`
17		Source      string      `yaml:"source"`
