27	// installedStatePath returns the path to ~/.ddx/installed.yaml.
28	func installedStatePath() (string, error) {
29		home, err := os.UserHomeDir()
30		if err != nil {
31			return "", fmt.Errorf("cannot determine home directory: %w", err)
32		}
33		return filepath.Join(home, ".ddx", "installed.yaml"), nil
34	}
35	
36	// LoadState reads installed.yaml, returning an empty state if the file doesn't exist.
37	func LoadState() (*InstalledState, error) {
38		path, err := installedStatePath()
39		if err != nil {
40			return nil, err
41		}
42	
43		data, err := os.ReadFile(path)
44		if os.IsNotExist(err) {
45			return &InstalledState{}, nil
46		}
47		if err != nil {
48			return nil, fmt.Errorf("reading installed state: %w", err)
49		}
50	
51		var state InstalledState
52		if err := yaml.Unmarshal(data, &state); err != nil {
53			return nil, fmt.Errorf("parsing installed state: %w", err)
54		}
55		return &state, nil
56	}
57	
58	// SaveState writes installed.yaml.
59	func SaveState(state *InstalledState) error {
60		path, err := installedStatePath()
61		if err != nil {
62			return err
63		}
64	
65		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
66			return fmt.Errorf("creating ~/.ddx directory: %w", err)
67		}
68	
69		data, err := yaml.Marshal(state)
70		if err != nil {
71			return fmt.Errorf("marshaling installed state: %w", err)
72		}
73	
74		if err := os.WriteFile(path, data, 0644); err != nil {
75			return fmt.Errorf("writing installed state: %w", err)
76		}
77		return nil
78	}
