1930	func (s *Server) handleAgentWorkers(w http.ResponseWriter, r *http.Request) {
1931		// Scoped/singleton: return workers for just the resolved project.
1932		if _, ok := projectFromContext(r.Context()); ok {
1933			m := s.workerManagerForRequest(r)
1934			recs, err := m.List()
1935			if err != nil {
1936				writeJSON(w, http.StatusOK, []WorkerRecord{})
1937				return
1938			}
1939			sort.Slice(recs, func(i, j int) bool {
1940				return recs[i].StartedAt.After(recs[j].StartedAt)
1941			})
1942			writeJSON(w, http.StatusOK, recs)
1943			return
1944		}
1945	
1946		projects := s.state.GetProjects()
1947	
1948		var all []WorkerRecord
1949		seen := map[string]bool{}
1950	
1951		for _, proj := range projects {
1952			var m *WorkerManager
1953			if proj.Path == s.WorkingDir {
1954				m = s.workers
1955			} else {
1956				m = NewWorkerManager(proj.Path)
1957			}
1958			recs, err := m.List()
1959			if err != nil {
1960				continue
1961			}
1962			for _, rec := range recs {
1963				if !seen[rec.ID] {
1964					all = append(all, rec)
1965					seen[rec.ID] = true
1966				}
1967			}
1968		}
1969	
1970		sort.Slice(all, func(i, j int) bool {
1971			return all[i].StartedAt.After(all[j].StartedAt)
1972		})
1973	
1974		writeJSON(w, http.StatusOK, all)
1975	}
