1992	func (s *Server) handleStartExecuteLoopWorker(w http.ResponseWriter, r *http.Request) {
1993		if !isTrusted(r) {
1994			writeJSON(w, http.StatusForbidden, map[string]string{"error": "dispatch endpoints are localhost-only"})
1995			return
1996		}
1997		var req struct {
1998			ProjectRoot   string `json:"project_root"`
1999			Harness       string `json:"harness"`
2000			Model         string `json:"model"`
2001			Profile       string `json:"profile"`
2002			Provider      string `json:"provider"`
2003			ModelRef      string `json:"model_ref"`
2004			Effort        string `json:"effort"`
2005			LabelFilter   string `json:"label_filter"`
2006			Once          bool   `json:"once"`
2007			PollInterval  string `json:"poll_interval"`
2008			NoReview      bool   `json:"no_review"`
2009			ReviewHarness string `json:"review_harness"`
2010			ReviewModel   string `json:"review_model"`
2011			MinTier       string `json:"min_tier"`
2012			MaxTier       string `json:"max_tier"`
2013		}
2014		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
2015			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid request body"})
2016			return
2017		}
2018	
2019		// Resolve project_root: if provided, validate it against registered projects.
2020		// An empty project_root means "use the server's primary project" (default).
2021		projectRoot := req.ProjectRoot
2022		if projectRoot != "" {
2023			resolved := s.resolveRequestedProject(projectRoot)
2024			if resolved == "" {
2025				writeJSON(w, http.StatusUnprocessableEntity, map[string]string{
2026					"error": fmt.Sprintf("no registered project matches %q; ensure the server was started from or has registered that project root", projectRoot),
2027				})
2028				return
2029			}
2030			projectRoot = resolved
2031		}
2032	
2033		var pollInterval time.Duration
2034		if strings.TrimSpace(req.PollInterval) != "" {
2035			d, err := time.ParseDuration(req.PollInterval)
2036			if err != nil {
2037				writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid poll_interval"})
2038				return
2039			}
2040			pollInterval = d
2041		}
2042		record, err := s.workers.StartExecuteLoop(ExecuteLoopWorkerSpec{
2043			ProjectRoot:   projectRoot,
2044			Harness:       req.Harness,
2045			Model:         req.Model,
2046			Profile:       req.Profile,
2047			Provider:      req.Provider,
2048			ModelRef:      req.ModelRef,
2049			Effort:        req.Effort,
2050			LabelFilter:   req.LabelFilter,
2051			Once:          req.Once,
2052			PollInterval:  pollInterval,
2053			NoReview:      req.NoReview,
2054			ReviewHarness: req.ReviewHarness,
2055			ReviewModel:   req.ReviewModel,
2056			MinTier:       req.MinTier,
2057			MaxTier:       req.MaxTier,
2058		})
2059		if err != nil {
2060			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
2061			return
2062		}
2063		writeJSON(w, http.StatusCreated, record)
2064	}
