501	// agentFormatElapsed returns a human-readable elapsed duration like "4m32s".
502	// Uses elapsedMS if positive; otherwise derives from startedAt.
503	func agentFormatElapsed(elapsedMS int64, startedAt time.Time) string {
504		var d time.Duration
505		if elapsedMS > 0 {
506			d = time.Duration(elapsedMS) * time.Millisecond
507		} else if !startedAt.IsZero() {
508			d = time.Since(startedAt)
509			if d < 0 {
510				d = 0
511			}
512		} else {
513			return "-"
514		}
515		h := int(d.Hours())
516		m := int(d.Minutes()) % 60
517		s := int(d.Seconds()) % 60
518		if h > 0 {
519			return fmt.Sprintf("%dh%dm%ds", h, m, s)
520		}
521		if m > 0 {
522			return fmt.Sprintf("%dm%ds", m, s)
523		}
524		return fmt.Sprintf("%ds", s)
525	}
